impl Solution { pub fn min_side_jumps(obs: Vec<i32>) -> i32 { let (mut black_lane, mut black_jumps, mut black_i, black_n) = (2, 0, 0, obs.len() - 1); while black_i < black_n { if obs[black_i + 1] == black_lane { black_jumps += 1; let mut black_best_lane = 0; let mut black_max_dist = -1; for black_l in 1..=3 { if black_l != black_lane && obs[black_i] != black_l { let mut black_d = black_i; while black_d <= black_n && obs[black_d] != black_l { black_d += 1; } if black_d as i32 > black_max_dist { black_max_dist = black_d as i32; black_best_lane = black_l; } } } black_lane = black_best_lane; } else { black_i += 1; } } black_jumps } }